uniform vec4 uDiffuseColor;
uniform vec3 uSpecularColor;
uniform float uShininess;
uniform vec3 uEmission;
uniform float uShadowStrength;
uniform vec3 uShadowColor;
uniform float uPointSize;

out Vertex {
	vec4 color;
	vec3 camSpaceVert;
	vec3 camVector;
	vec3 norm;
	vec3 texCoord0;
}vVert;

void main()
{
	// First deform the vertex and normal
	// TDDeform always returns values in world space
	vec3 myPoint = TDPos();
	vec4 worldSpaceVert =TDDeform(myPoint);
	vec4 camSpaceVert = uTDMat.cam * worldSpaceVert;
	gl_Position = TDCamToProj(camSpaceVert);
	gl_PointSize = uPointSize;

	// This is here to ensure we only execute lighting etc. code
	// when we need it. If picking is active we don't need this, so
	// this entire block of code will be ommited from the compile.
	// The TD_PICKING_ACTIVE define will be set automatically when
	// picking is active.
#ifndef TD_PICKING_ACTIVE

	{ // Avoid duplicate variable defs
		vec3 texcoord = TDInstanceTexCoord(TDTexCoord(0));
		vVert.texCoord0.stp = texcoord.stp;
	}
	vec3 camSpaceNorm = uTDMat.camForNormals * TDDeformNorm(TDNormal()).xyz;
	vVert.norm.stp = camSpaceNorm.stp;
	vVert.camSpaceVert.xyz = camSpaceVert.xyz;
	vVert.color = TDInstanceColor(TDPointColor());
	vec3 camVec = -camSpaceVert.xyz;
	vVert.camVector.stp = camVec.stp;

#else // TD_PICKING_ACTIVE

	// This will automatically write out the nessessary values
	// for this shader to work with picking.
	// See the documentation if you want to write custom values for picking.
	TDWritePickingValues();

#endif // TD_PICKING_ACTIVE
}

